// Package editor handles editor command execution.
package editor

import (
	"context"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strings"
	"time"

	"github.com/foxytanuki/rcode/internal/logger"
)

var (
	// ErrExecutionFailed is returned when command execution fails
	ErrExecutionFailed = errors.New("command execution failed")
	// ErrTimeout is returned when command execution times out
	ErrTimeout = errors.New("command execution timeout")
)

// Executor handles the execution of editor commands
type Executor struct {
	manager *Manager
	log     *logger.Logger
	timeout time.Duration
}

// ExecutorOption is a functional option for configuring the executor
type ExecutorOption func(*Executor)

// WithTimeout sets the execution timeout
func WithTimeout(timeout time.Duration) ExecutorOption {
	return func(e *Executor) {
		e.timeout = timeout
	}
}

// NewExecutor creates a new executor
func NewExecutor(manager *Manager, log *logger.Logger, opts ...ExecutorOption) *Executor {
	e := &Executor{
		manager: manager,
		log:     log,
		timeout: 30 * time.Second, // Default timeout
	}

	for _, opt := range opts {
		opt(e)
	}

	return e
}

// Execute opens a file/directory in the specified editor
func (e *Executor) Execute(editorName string, vars TemplateVars) error {
	// Validate variables
	if err := ValidateVars(vars); err != nil {
		return fmt.Errorf("invalid variables: %w", err)
	}

	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return err
	}

	// Check availability
	if !e.manager.IsAvailable(editor.Name) {
		e.log.Warn("Editor not available, attempting anyway",
			"editor", editor.Name,
		)
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Log the execution
	e.log.Info("Executing editor command",
		"editor", editor.Name,
		"command", command,
		"user", vars.User,
		"host", vars.Host,
		"path", vars.Path,
	)

	// Execute the command
	if err := e.executeCommand(command); err != nil {
		return fmt.Errorf("%w: %v", ErrExecutionFailed, err)
	}

	e.log.Info("Editor launched successfully",
		"editor", editor.Name,
		"path", vars.Path,
	)

	return nil
}

// ExecuteDefault opens a file/directory in the default editor
func (e *Executor) ExecuteDefault(vars TemplateVars) error {
	editor, err := e.manager.GetDefaultEditor()
	if err != nil {
		return err
	}

	return e.Execute(editor.Name, vars)
}

// executeCommand executes the editor command
func (e *Executor) executeCommand(command string) error {
	// Parse command
	executable, args := ParseCommand(command)
	if executable == "" {
		return errors.New("empty command")
	}

	// Create command - args are passed separately to prevent shell injection
	cmd := exec.Command(executable, args...) // #nosec G204

	// For GUI editors, we want to detach from the parent process
	cmd.Stdout = nil
	cmd.Stderr = nil
	cmd.Stdin = nil

	// Set environment variables if needed
	cmd.Env = os.Environ()

	// Start the command
	if err := cmd.Start(); err != nil {
		return fmt.Errorf("failed to start editor: %w", err)
	}

	// For GUI applications, release the process so we don't wait
	if err := cmd.Process.Release(); err != nil {
		// Non-critical error, just log it
		e.log.Debug("Failed to release process", "error", err)
	}

	return nil
}

// ExecuteWithContext executes a command with a context for cancellation
func (e *Executor) ExecuteWithContext(ctx context.Context, editorName string, vars TemplateVars) error {
	// Create a channel to signal completion
	done := make(chan error, 1)

	// Execute in a goroutine
	go func() {
		done <- e.Execute(editorName, vars)
	}()

	// Wait for completion or context cancellation
	select {
	case err := <-done:
		return err
	case <-ctx.Done():
		return fmt.Errorf("%w: %v", ErrTimeout, ctx.Err())
	}
}

// ExecuteAndWait executes a command and waits for it to complete
func (e *Executor) ExecuteAndWait(editorName string, vars TemplateVars) error {
	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return err
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Parse command
	executable, args := ParseCommand(command)
	if executable == "" {
		return errors.New("empty command")
	}

	// Create command with context for timeout
	ctx, cancel := context.WithTimeout(context.Background(), e.timeout)
	defer cancel()

	// Args are passed separately to prevent shell injection
	cmd := exec.CommandContext(ctx, executable, args...) // #nosec G204

	// Log the execution
	e.log.Debug("Executing and waiting for editor",
		"editor", editor.Name,
		"command", command,
		"timeout", e.timeout,
	)

	// Run the command and wait for completion
	output, err := cmd.CombinedOutput()
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			return fmt.Errorf("%w after %v", ErrTimeout, e.timeout)
		}
		return fmt.Errorf("%w: %v (output: %s)", ErrExecutionFailed, err, string(output))
	}

	return nil
}

// TestCommand tests if a command can be executed without actually running it
func (e *Executor) TestCommand(editorName string, vars TemplateVars) error {
	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return err
	}

	// Validate variables
	if err := ValidateVars(vars); err != nil {
		return fmt.Errorf("invalid variables: %w", err)
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Parse command
	executable, _ := ParseCommand(command)
	if executable == "" {
		return errors.New("empty command")
	}

	// Check if executable exists
	if _, err := exec.LookPath(executable); err != nil {
		return fmt.Errorf("executable not found: %w", err)
	}

	return nil
}

// ListAvailableEditors returns a list of available editors
func (e *Executor) ListAvailableEditors() []string {
	editors := e.manager.ListEditors()
	available := make([]string, 0, len(editors))

	for _, editor := range editors {
		if e.manager.IsAvailable(editor.Name) {
			available = append(available, editor.Name)
		}
	}

	return available
}

// GetEditorCommand returns the rendered command for an editor
func (e *Executor) GetEditorCommand(editorName string, vars TemplateVars) (string, error) {
	// Get the editor
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return "", err
	}

	// Render the command template
	command, err := editor.Template.Render(vars)
	if err != nil {
		return "", fmt.Errorf("failed to render template: %w", err)
	}

	return command, nil
}

// ExecuteCustom executes a custom command with the given template
func (e *Executor) ExecuteCustom(commandTemplate string, vars TemplateVars) error {
	// Create a temporary template
	template, err := NewTemplate(commandTemplate)
	if err != nil {
		return fmt.Errorf("invalid template: %w", err)
	}

	// Render the command
	command, err := template.Render(vars)
	if err != nil {
		return fmt.Errorf("failed to render template: %w", err)
	}

	// Log the execution
	e.log.Debug("Executing custom command",
		"command", command,
		"user", vars.User,
		"host", vars.Host,
		"path", vars.Path,
	)

	// Execute the command
	if err := e.executeCommand(command); err != nil {
		return fmt.Errorf("%w: %v", ErrExecutionFailed, err)
	}

	return nil
}

// RefreshAvailability refreshes the availability status of all editors
func (e *Executor) RefreshAvailability() {
	e.manager.RefreshAvailability()
}

// SupportsRemoteEditing checks if an editor supports remote editing
func (e *Executor) SupportsRemoteEditing(editorName string) bool {
	editor, err := e.manager.GetEditor(editorName)
	if err != nil {
		return false
	}

	// Check if the command template includes host/user variables
	return editor.Template.RequiresHost() || editor.Template.RequiresUser()
}

// NormalizeEditorName normalizes an editor name for case-insensitive lookup
func NormalizeEditorName(name string) string {
	return strings.ToLower(strings.TrimSpace(name))
}

// Package main implements the rcode server application.
package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"os/exec"
	"strings"
	"time"

	"github.com/foxytanuki/rcode/internal/editor"
	"github.com/foxytanuki/rcode/internal/logger"
	"github.com/foxytanuki/rcode/internal/version"
	"github.com/foxytanuki/rcode/pkg/api"
)

// handleHealth handles GET /health
func (s *Server) handleHealth(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		s.respondError(w, api.ErrNotImplemented, http.StatusMethodNotAllowed, "Method not allowed")
		return
	}

	uptime := time.Since(s.startTime).Seconds()
	response := api.HealthResponse{
		Status:    "healthy",
		Version:   version.Version,
		Uptime:    int64(uptime),
		StartedAt: s.startTime,
	}
	response.SetTimestamp()

	s.respondJSON(w, http.StatusOK, response)
}

// handleEditors handles GET /editors
func (s *Server) handleEditors(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		s.respondError(w, api.ErrNotImplemented, http.StatusMethodNotAllowed, "Method not allowed")
		return
	}

	editorList := s.editor.ListEditors()
	editors := make([]api.EditorInfo, 0, len(editorList))

	for _, e := range editorList {
		info := api.EditorInfo{
			Name:      e.Name,
			Command:   e.Command,
			Available: e.Available,
			Default:   e.Default,
		}
		editors = append(editors, info)
	}

	response := api.EditorsResponse{
		Editors:       editors,
		DefaultEditor: s.editor.GetDefaultName(),
	}
	response.SetTimestamp()

	s.respondJSON(w, http.StatusOK, response)
}

// handleOpenEditor handles POST /open-editor
func (s *Server) handleOpenEditor(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		s.respondError(w, api.ErrNotImplemented, http.StatusMethodNotAllowed, "Method not allowed")
		return
	}

	// Parse request body
	var req api.OpenRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		s.respondError(w, api.ErrInvalidRequest, http.StatusBadRequest, fmt.Sprintf("Invalid JSON: %v", err))
		return
	}

	// Validate request
	if err := req.Validate(); err != nil {
		s.respondError(w, err, http.StatusBadRequest, "")
		return
	}

	// Log the request
	s.log.Info("Open editor request",
		"path", req.Path,
		"editor", req.Editor,
		"user", req.User,
		"host", req.Host,
		"remote_addr", r.RemoteAddr,
	)

	// Look up editor via Manager
	e, err := s.editor.GetEditor(req.Editor)
	if err != nil {
		s.log.Error("Failed to find editor",
			"error", err,
			"editor", req.Editor,
		)

		statusCode := http.StatusInternalServerError
		if errors.Is(err, editor.ErrEditorNotFound) || errors.Is(err, editor.ErrNoDefaultEditor) {
			statusCode = http.StatusNotFound
		}

		s.respondError(w, err, statusCode, "")
		return
	}

	// Build template variables and render command
	vars := editor.TemplateVars{
		User: req.User,
		Host: req.Host,
		Path: req.Path,
	}

	command, err := e.Template.Render(vars)
	if err != nil {
		s.log.Error("Failed to render editor command",
			"error", err,
			"editor", e.Name,
			"path", req.Path,
		)
		s.respondError(w, err, http.StatusInternalServerError, "")
		return
	}

	// Execute the command
	if err := executeCommand(command, s.log); err != nil {
		s.log.Error("Failed to execute editor command",
			"error", err,
			"editor", e.Name,
			"command", command,
		)
		s.respondError(w, err, http.StatusInternalServerError, "")
		return
	}

	editorName := req.Editor
	if editorName == "" {
		editorName = e.Name
	}

	// Success response
	response := api.OpenResponse{
		Success: true,
		Message: fmt.Sprintf("Opened %s in %s", req.Path, editorName),
		Editor:  editorName,
		Command: command,
	}
	response.SetTimestamp()

	s.respondJSON(w, http.StatusOK, response)
}

// respondJSON sends a JSON response
func (s *Server) respondJSON(w http.ResponseWriter, status int, data interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)

	if err := json.NewEncoder(w).Encode(data); err != nil {
		s.log.Error("Failed to encode JSON response", "error", err)
	}
}

// respondError sends an error response
func (s *Server) respondError(w http.ResponseWriter, err error, status int, details string) {
	response := api.NewErrorResponse(err, api.GetErrorCode(err), details)

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)

	if encodeErr := json.NewEncoder(w).Encode(response); encodeErr != nil {
		s.log.Error("Failed to encode error response", "error", encodeErr)
	}
}

// executeCommand executes an editor command string, detaching the process for GUI editors.
func executeCommand(command string, log *logger.Logger) error {
	parts := strings.Fields(command)
	if len(parts) == 0 {
		return fmt.Errorf("empty command")
	}

	executable := parts[0]
	args := parts[1:]

	cmd := exec.Command(executable, args...) // #nosec G204
	cmd.Stdout = nil
	cmd.Stderr = nil
	cmd.Stdin = nil

	if err := cmd.Start(); err != nil {
		return fmt.Errorf("failed to start command: %w", err)
	}

	if err := cmd.Process.Release(); err != nil {
		log.Warn("Failed to release process", "error", err)
	}

	return nil
}

